def setup_secure_logging(
    log_dir: str = None,
    log_filename: str = "application.log",
    max_bytes: int = 5 * 1024 * 1024,  # 5 MB
    backup_count: int = 5,
    log_level: int = logging.INFO,
    console_output: bool = True,
) -> logging.Logger:
    """
    Set up secure application logging with rotation and proper file permissions.
    
    Args:
        log_dir: Directory for log files. Defaults to a secure temp directory.
        log_filename: Name of the log file.
        max_bytes: Maximum size of each log file before rotation.
        backup_count: Number of backup log files to keep.
        log_level: Logging level.
        console_output: Whether to also log to console.
    
    Returns:
        Configured logger instance.
    """
    # Validate and sanitize log filename
    log_filename = os.path.basename(log_filename)
    if not log_filename or log_filename.startswith('.'):
        raise ValueError("Invalid log filename provided.")

    # Set up log directory
    if log_dir is None:
        log_dir = os.path.join(tempfile.gettempdir(), "secure_app_logs")

    # Resolve to absolute path and prevent path traversal
    log_dir = os.path.realpath(os.path.abspath(log_dir))

    # Create log directory with restricted permissions if it doesn't exist
    if not os.path.exists(log_dir):
        try:
            os.makedirs(log_dir, mode=0o700, exist_ok=False)
        except FileExistsError:
            pass  # Race condition safe
        except OSError as e:
            raise RuntimeError(f"Failed to create log directory: {e}")
    
    # Verify directory ownership (should be owned by current user)
    dir_stat = os.stat(log_dir)
    if dir_stat.st_uid != os.getuid():
        raise RuntimeError(
            f"Log directory '{log_dir}' is not owned by the current user. "
            "This could indicate a security issue."
        )

    # Ensure directory permissions are restrictive
    os.chmod(log_dir, stat.S_IRWXU)  # 700 - owner only

    log_filepath = os.path.join(log_dir, log_filename)

    # Verify the resolved path is still within the intended directory
    if not os.path.realpath(log_filepath).startswith(os.path.realpath(log_dir)):
        raise ValueError("Log file path escapes the log directory (path traversal detected).")

    # Create logger
    logger = logging.getLogger("secure_app")
    logger.setLevel(log_level)

    # Clear any existing handlers to prevent duplicates
    logger.handlers.clear()

    # Define log format - avoid logging sensitive data
    log_format = logging.Formatter(
        fmt="%(asctime)s | %(levelname)-8s | %(name)s | %(module)s:%(funcName)s:%(lineno)d | %(message)s",
        datefmt="%Y-%m-%d %H:%M:%S",
    )

    # Set up rotating file handler
    try:
        file_handler = logging.handlers.RotatingFileHandler(
            filename=log_filepath,
            maxBytes=max_bytes,
            backupCount=backup_count,
            encoding="utf-8",
        )
        file_handler.setLevel(log_level)
        file_handler.setFormatter(log_format)

        # Custom namer to ensure rotated files also get proper permissions
        original_namer = file_handler.namer if hasattr(file_handler, 'namer') and file_handler.namer else None

        def secure_namer(name):
            if original_namer:
                return original_namer(name)
            return name

        def secure_rotator(source, dest):
            """Custom rotator that sets secure permissions on rotated files."""
            os.rename(source, dest)
            _set_secure_file_permissions(dest)

        file_handler.namer = secure_namer
        file_handler.rotator = secure_rotator

        logger.addHandler(file_handler)

        # Set secure permissions on the main log file
        _set_secure_file_permissions(log_filepath)

    except (OSError, IOError) as e:
        raise RuntimeError(f"Failed to set up log file handler: {e}")

    # Set up timed rotating handler for daily rotation as well
    try:
        timed_log_filepath = os.path.join(log_dir, f"daily_{log_filename}")
        
        # Verify path safety
        if not os.path.realpath(timed_log_filepath).startswith(os.path.realpath(log_dir)):
            raise ValueError("Timed log file path escapes the log directory.")

        timed_handler = logging.handlers.TimedRotatingFileHandler(
            filename=timed_log_filepath,
            when="midnight",
            interval=1,
            backupCount=backup_count,
            encoding="utf-8",
            utc=True,
        )
        timed_handler.setLevel(log_level)
        timed_handler.setFormatter(log_format)

        def timed_secure_rotator(source, dest):
            os.rename(source, dest)
            _set_secure_file_permissions(dest)

        timed_handler.rotator = timed_secure_rotator
        logger.addHandler(timed_handler)

        _set_secure_file_permissions(timed_log_filepath)

    except (OSError, IOError) as e:
        logger.warning(f"Failed to set up timed rotating handler: {e}")

    # Console handler (optional)
    if console_output:
        console_handler = logging.StreamHandler(sys.stdout)
        console_handler.setLevel(log_level)
        console_format = logging.Formatter(
            fmt="%(asctime)s | %(levelname)-8s | %(message)s",
            datefmt="%H:%M:%S",
        )
        console_handler.setFormatter(console_format)
        logger.addHandler(console_handler)

    # Prevent log propagation to root logger
    logger.propagate = False

    logger.info(f"Logging initialized. Log directory: {log_dir}")
    logger.info(f"Log rotation: max {max_bytes} bytes, {backup_count} backups")

