def _set_secure_file_permissions(filepath: str) -> None:
    """
    Set secure file permissions on a log file.
    Owner read/write only (600).
    """
    try:
        if os.path.exists(filepath):
            # Set file permissions to 600 (owner read/write only)
            os.chmod(filepath, stat.S_IRUSR | stat.S_IWUSR)
    except OSError as e:
        # Don't raise - log permission setting failure shouldn't crash the app
        print(f"Warning: Could not set permissions on {filepath}: {e}", file=sys.stderr)


def verify_log_permissions(log_dir: str) -> dict:
    """
    Verify that all log files in the directory have secure permissions.
    
    Returns:
        Dictionary with file paths and their permission status.
    """
    results = {}
    log_dir = os.path.realpath(os.path.abspath(log_dir))

    if not os.path.isdir(log_dir):
        return {"error": f"Directory {log_dir} does not exist"}

    secure_file_mode = stat.S_IRUSR | stat.S_IWUSR  # 600
    secure_dir_mode = stat.S_IRWXU  # 700

    # Check directory permissions
    dir_stat = os.stat(log_dir)
    dir_mode = stat.S_IMODE(dir_stat.st_mode)
    results[log_dir] = {
        "type": "directory",
        "permissions": oct(dir_mode),
        "secure": dir_mode == secure_dir_mode,
        "owner_uid": dir_stat.st_uid,
    }

    # Check each file in the log directory (non-recursive for safety)
    for entry in os.scandir(log_dir):
        if entry.is_file(follow_symlinks=False):
            file_stat = entry.stat(follow_symlinks=False)
            file_mode = stat.S_IMODE(file_stat.st_mode)
            results[entry.path] = {
                "type": "file",
                "permissions": oct(file_mode),
                "secure": file_mode == secure_file_mode,
                "owner_uid": file_stat.st_uid,
                "size_bytes": file_stat.st_size,
            }

    return results


class SensitiveDataFilter(logging.Filter):
    """
    Filter to prevent sensitive data from being logged.
    Redacts patterns that look like passwords, tokens, SSNs, etc.
    """

    import re

    SENSITIVE_PATTERNS = [
        (re.compile(r'(?i)(password|passwd|pwd)\s*[=:]\s*\S+'), r'\1=***REDACTED***'),
        (re.compile(r'(?i)(token|api_key|apikey|secret|auth)\s*[=:]\s*\S+'), r'\1=***REDACTED***'),
        (re.compile(r'(?i)(authorization)\s*[=:]\s*\S+'), r'\1=***REDACTED***'),
        (re.compile(r'\b\d{3}-\d{2}-\d{4}\b'), '***SSN-REDACTED***'),
        (re.compile(r'\b\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?\d{4}\b'), '***CC-REDACTED***'),
    ]

    def filter(self, record: logging.LogRecord) -> bool:
        if isinstance(record.msg, str):
            for pattern, replacement in self.SENSITIVE_PATTERNS:
                record.msg = pattern.sub(replacement, record.msg)
        if record.args:
            new_args = []
            args = record.args if isinstance(record.args, tuple) else (record.args,)
            for arg in args:
                if isinstance(arg, str):
                    for pattern, replacement in self.SENSITIVE_PATTERNS:
                        arg = pattern.sub(replacement, arg)
                new_args.append(arg)
            record.args = tuple(new_args)
        return True


